SERVICE_NAME = "debug.DebugService"


class DebugService:
    def __init__(self):
        self._lock = threading.Lock()
        self._counter = 0
        self._last_request = None
        self._last_peer = None
        self._last_metadata = None

    def state(self) -> Dict[str, Any]:
        with self._lock:
            return {
                "counter": self._counter,
                "last_request": _sanitize_value(self._last_request, max_value_len=1024, max_container_items=50, max_depth=3),
                "last_peer": self._last_peer,
                "last_metadata": _sanitize_value(self._last_metadata, max_value_len=1024, max_container_items=50, max_depth=3),
                "thread": threading.current_thread().name,
            }

    def Ping(self, request: wrappers_pb2.StringValue, context: grpc.ServicerContext) -> wrappers_pb2.StringValue:
        with self._lock:
            self._counter += 1
            self._last_request = request.value
            try:
                self._last_peer = context.peer()
            except Exception:
                self._last_peer = None
            try:
                self._last_metadata = _metadata_to_dict(context.invocation_metadata())
            except Exception:
                self._last_metadata = None
